  name_zh = '上海气象博物馆（徐家汇观象台旧址）',
  name_en = '上海气象博物馆（徐家汇观象台旧址）',
  body = '<p>Detailed Address: No. 166 Puxi Road, Xuhui District, Shanghai Ticket Information: Free admission, but reservations are required via the "Shanghai Meteorological Museum" WeChat account; daily slots are limited. Groups of 5 or more should book at least one week ahead for the free guided tour. Opening Hours: Tuesday to Sunday 9:00–11:30 (last entry 11:00) and 13:30–16:30 (last entry 16:00); closed Mondays, except on national holidays. Transportation: Subway Lines 1/9/11 to Xujiahui Station, Exit 8, about an 8-minute walk; or Lines 1/4 to Shanghai Stadium, Exit 8, about a 10-minute walk. Buses 42/43/50/167/824/946 stop at Xujiahui.</p>',
  updated_at = NOW()
