  name_en = '上海电影博物馆',
  body = '<p>Detailed Address: No. 595 Caoxi North Road, Xuhui District, Shanghai Ticket Information: Adult ticket 60 yuan; student and senior (60–64) tickets 30 yuan; free for children under 1.3m, seniors 65+, and disabled visitors. Opening Hours: Tuesday to Friday 9:30–16:30 (last entry 16:00); Saturday, Sunday, and national holidays 9:30–17:00; closed Mondays. Transportation: Subway Lines 1/4 to Shanghai Stadium, Exit 6, about a 5-minute walk. Buses 49/50/218/315/703/704/712/926 stop at Shanghai Stadium.</p>',
