UPDATE sub_areas SET
  name_zh = '土山湾博物馆',
  name_en = '土山湾博物馆',
  body = '<p>Detailed Address: No. 55 Puhuitang Road, Xuhui District, Shanghai Ticket Information: Free admission, no reservation required. Groups of 5 or more can book a free guided tour at least one week in advance. Opening Hours: Tuesday to Sunday in two sessions: 9:00–11:30 (last entry 11:00) and 13:00–16:30 (last entry 16:00); closed Mondays, except on national holidays. Transportation: Subway Lines 1/9/11 to Xujiahui Station, Exit 1, about an 8-minute walk; or Lines 1/4 to Shanghai Stadium, Exit 8, about a 5-minute walk. Buses 42/43/50/703/754/824/923/946 stop at Xujiahui or Caoxi North Road/Puhuitang Road.</p>',
