UPDATE sub_areas SET
  name_zh = '圣母院旧址（上海老站）',
  name_en = '圣母院旧址（上海老站）',
  body = '<p>Detailed Address: No. 221 Puxi Road, Xuhui District, Shanghai (near Xujiahui Catholic Church) Ticket Information: No admission ticket as a dining venue. The exterior is freely viewable at any time. Interior access requires dining or event reservation; average spend 200–400 yuan per person (2025 market price). Opening Hours: As a restaurant, year-round 11:30–14:00 and 17:00–22:00 (extended on holidays); building exterior viewable 24 hours. Transportation: Subway Lines 1/9/11 to Xujiahui Station, Exit 3, about a 3-minute walk. Buses 42/43/50/167/198/824/926/946 stop at Xujiahui. The building is directly south of Xujiahui Catholic Church.</p>',
  updated_at = NOW()
