UPDATE sub_areas SET
  name_zh = '名字：大足石刻博物馆',
  name_en = 'Dazu Rock Carvings Museum',
  body = '<p>D 扫描、全息投影、AR 互动等数字化手段复原千手千眼观音、九龙浴太子、华严三圣等代表性龛窟。博物馆实行实名制预约免费参观，是游客抵达宝顶山后先学后游的最佳去处。</p>',
  updated_at = NOW()
WHERE id = 'chongqing_dazu_rock_carvings_sa_03';

